
import {ipcMain, app, BrowserWindow} from 'electron';
import {Log} from 'jibo-log';
import parentLog from  '../../log';

Log.processName = "skill";
const log = parentLog.createChild("SkillsMainProcess");
log.debug('skills-main-process.ts');


class RendererController {

    private static WIDTH:number = 1281;
    private static HEIGHT:number = 721;

    private window:BrowserWindow;

    constructor(private registryHost:string, private indexPath:string, private context) {

        //function bindings
        this.onReady = this.onReady.bind(this);
        this.onInit = this.onInit.bind(this);
        this.onFinished = this.onFinished.bind(this);
        this.onGetContext = this.onGetContext.bind(this);
        this.onCrashed = this.onCrashed.bind(this);

        //listen for renderer process events
        ipcMain.on('get-context', this.onGetContext);
        ipcMain.on('init-done', this.onInit);

        app.once('ready', this.onReady);
    }


    private onCrashed() {
        log.warn('Renderer process crashed. Restarting.');
        this.window.reload();
    }

    /**
     * Called when the websocket connection opens. Once we have a connection, then create the
     * renderer process
     */
    private onReady():void {
        log.info('App Ready', this.indexPath);

        this.window = new BrowserWindow({
            show: false,
            x: 0,
            y: 0,
            width: RendererController.WIDTH,
            height: RendererController.HEIGHT,
            frame: false
        });

        this.window.webContents.on('crashed', this.onCrashed);
        this.window.loadURL('file://' + this.indexPath);

        //You'd think this wouldn't be necessary, but whatchagonnado?
        this.window.setSize(RendererController.WIDTH, RendererController.HEIGHT);
    }

    private onFinished():void {
        app.quit();
    }

    /**
     * Called by the SSM when all of it's load masking is done
     */
    private onInit(): void {
        this.window.show();
        this.window.focus();
        this.window.setPosition(0, 0);
    }

    /**
     * Called by renderer process when the `jibo` module requests initialization data
     * @param event
     */
    private onGetContext(event):void {
        log.info('Get context called');
        event.sender.send('set-context', {
            registryHost: this.registryHost,
            runMode: process.env.RUNMODE,
            token: '',
            context: this.context
        });
    }


}

export default function(registryHost:string, indexPath:string, context:any):RendererController {
    return new RendererController(registryHost, indexPath, context);
}
